import assert from"node:assert";import{Browser,BrowserPlatform,DefaultProvider}from"./main.js";describe("DefaultProvider",()=>{let r;beforeEach(()=>{r=new DefaultProvider}),describe("constructor",()=>{it("should create provider with default base URL",()=>{const r=new DefaultProvider;assert(r instanceof DefaultProvider)}),it("should create provider with custom base URL",()=>{const r=new DefaultProvider("https://custom.example.com/");assert(r instanceof DefaultProvider)})}),describe("BrowserProvider interface compliance",()=>{it("should implement supports method",()=>{assert.strictEqual(typeof r.supports,"function")}),it("should implement getDownloadUrl method",()=>{assert.strictEqual(typeof r.getDownloadUrl,"function")}),it("should implement getExecutablePath method",()=>{assert.strictEqual(typeof r.getExecutablePath,"function")})}),describe("basic functionality",()=>{it("should handle different browsers",()=>{const e=r.supports({browser:Browser.CHROME,platform:BrowserPlatform.LINUX,buildId:"120.0.6099.109"});assert.strictEqual(e,!0)}),it("should handle different platforms",()=>{const e=r.supports({browser:Browser.CHROME,platform:BrowserPlatform.MAC,buildId:"120.0.6099.109"});assert.strictEqual(e,!0)}),it("should handle ChromeDriver",()=>{const e=r.supports({browser:Browser.CHROMEDRIVER,platform:BrowserPlatform.LINUX,buildId:"120.0.6099.109"});assert.strictEqual(e,!0)}),it("should return URL for valid build",()=>{const e=r.getDownloadUrl({browser:Browser.CHROME,platform:BrowserPlatform.LINUX,buildId:"120.0.6099.109"});assert(e instanceof URL),assert(e.toString().includes("120.0.6099.109"))})})});